            // stronger relevance.
            let dual_boost = if in_content && in_summary { 0.15 } else { 0.0 };

            // Cap each keyword's contribution at ~1.4× its base share.
            let contribution = base_share * (1.0 + freq_bonus + dual_boost);
            contribution.min(base_share * 1.4)
        })
        .sum();

    total.clamp(0.0, 1.0)
}

